import{_ as t,o as a,c as l,ag as o}from"./chunks/framework.DtEl18Xn.js";const p="/getbiji-docs-v3/images/XqSgbaMacou4h5xxLHDc4c0mnnb.png",e="/getbiji-docs-v3/images/Lo4tbV7fpo2kJcx3yUocfpBQnee.png",s="/getbiji-docs-v3/images/JE0eb40nIoXEYwxsnpjcnKHan7g.png",n="/getbiji-docs-v3/images/P4IxbZSwCoJbAmx4Lx5cuHHwnLb.png",c="/getbiji-docs-v3/images/KeMfbSdcQo5FpvxNn5ncFiUFnib.png",r="/getbiji-docs-v3/images/ChIHbRVFLo8GtpxoTIpcKj8Znwd.png",x=JSON.parse('{"title":"语音口令—说话就能划重点","description":"","frontmatter":{"title":"语音口令—说话就能划重点","category":" 如何快速上手记笔记","lastUpdated":"2026-03-14T14:55:22.383Z"},"headers":[],"relativePath":"-如何快速上手记笔记/语音口令说话就能划重点.md","filePath":"-如何快速上手记笔记/语音口令说话就能划重点.md"}'),_={name:"-如何快速上手记笔记/语音口令说话就能划重点.md"};function g(m,i,d,b,A,u){return a(),l("div",null,[...i[0]||(i[0]=[o('<h1 id="语音口令—说话就能划重点" tabindex="-1">语音口令—说话就能划重点 <a class="header-anchor" href="#语音口令—说话就能划重点" aria-label="Permalink to &quot;语音口令—说话就能划重点&quot;">​</a></h1><p>**语音口令——录音中说句话，AI 帮你标记重点 **</p><p>录音时说出口令词，AI 自动捕捉关键内容并特别处理</p><p>Get笔记全新推出语音口令功能，你可以自定义口令词和对应的处理要求。录音过程中，只需说出口令词，AI 就能自动识别并对相关内容做特别处理——标记重点、提炼金句、总结要点，动动嘴就能完成。</p><p><strong>适用场景</strong></p><ul><li>课堂听讲：老师讲到重点时，说一句「帮我记一下」，AI 自动捕捉该知识点并总结，不用暂停、不用切 App、不用打字，2小时的课10分钟就能复习完</li><li>读书思考：看到精彩段落念出来，说一句「这段不错」，手不离书、眼不离页面，看完后读书笔记自动整理好</li><li>灵感捕捉：开车、通勤时突然冒出好想法，说一句「这个想法记一下」，到了目的地灵感全都在，不会再丢了</li><li>听播客/音频节目：一边听一边录，听到有启发的观点说一句「这个有启发」，一期听完金句自动整理好——把「消费型听」变成「积累型听」</li><li>语音日记/个人复盘：每天录一段语音回顾，哪些特别想记住的说一句「这个很重要」，AI 生成日记时会把你标记的内容作为重点——重点由你自己决定</li><li>带娃记录：孩子突然说了句可爱的话，你正在忙没法掏手机，说一句「这句真可爱」就能记下来，等孩子长大这些就是最珍贵的回忆</li></ul><p><strong>核心功能</strong></p><ul><li>自定义口令词：支持设置最多 3 个口令词，每个口令词可指定不同的处理要求（如「帮我记一下」→ 捕捉知识点并总结，「这段不错」→ 提炼金句或精彩表达）</li><li>实时识别：录音过程中 AI 实时监听口令词，无需手动操作</li><li>智能处理：识别到口令词后，AI 自动对对应的录音内容按你设定的要求进行处理</li><li>标记整合：口令词触发的处理结果统一展示在笔记的「标记」tab 中，同时在智能总结中重点标注，方便快速回顾</li></ul><h1 id="app端——使用说明" tabindex="-1">APP端——使用说明 <a class="header-anchor" href="#app端——使用说明" aria-label="Permalink to &quot;APP端——使用说明&quot;">​</a></h1><ol><li>打开 App，进入「我的账号」页面，在常用操作区域点击「语音口令」</li><li>进入语音口令设置页，开启「开启语音口令功能」开关</li><li>点击「添加口令词」，输入你想使用的口令词（如「帮我记一下」），并填写对应的处理要求（如「捕捉当下讲到的知识点并总结」）</li><li>最多可添加 3 个口令词，设置完成后即可生效</li><li>正常使用录音功能，录音过程中需要标记时，直接说出口令词即可——AI 会在生成笔记时自动识别并处理</li><li>录音结束后，进入笔记详情，在「标记」tab 中查看所有口令词触发的处理结果，智能总结中也会对这些内容做重点标注</li></ol><p><img src="'+p+'" alt=""></p><p><img src="'+e+'" alt=""></p><p><img src="'+s+'" alt=""></p><p><img src="'+n+'" alt=""></p><p><img src="'+c+'" alt=""></p><p><img src="'+r+'" alt=""></p>',16)])])}const I=t(_,[["render",g]]);export{x as __pageData,I as default};
